import{_ as t,c as i,o as r,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.30：权限配置更方便，Todo 工具回归","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.30.md","filePath":"changelog/v1.1.30.md","lastUpdated":1772014034000}'),l={name:"changelog/v1.1.30.md"};function d(n,o,s,h,c,p){return r(),i("div",null,[...o[0]||(o[0]=[a('<h1 id="v1-1-30-权限配置更方便-todo-工具回归" tabindex="-1">v1.1.30：权限配置更方便，Todo 工具回归 <a class="header-anchor" href="#v1-1-30-权限配置更方便-todo-工具回归" aria-label="Permalink to “v1.1.30：权限配置更方便，Todo 工具回归”">​</a></h1><p><strong>发布日期</strong>：2026年01月21日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新让权限路径配置更灵活，同时为 OpenAI 模型找回了 Todo List 工具，让任务管理更顺手。</p><hr><h2 id="新功能-权限路径支持" tabindex="-1">新功能：权限路径支持 <code>~</code> <a class="header-anchor" href="#新功能-权限路径支持" aria-label="Permalink to “新功能：权限路径支持 ~”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在你在配置权限白名单时，可以使用 <code>~</code> 或 <code>$HOME</code> 来代表你的用户主目录了。</p><h3 id="为什么需要这个" tabindex="-1">为什么需要这个？ <a class="header-anchor" href="#为什么需要这个" aria-label="Permalink to “为什么需要这个？”">​</a></h3><p>以前配置路径必须写完整的绝对路径（比如 <code>/Users/yourname/projects</code>），很麻烦，而且在不同电脑上配置文件不能通用。现在你可以写 <code>~/projects</code>，不管在哪台电脑上，它都能自动识别为当前用户的主目录。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>在你的配置文件或启动参数中：</p>',13),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},`# 以前（必须写死）：
opencode --allow-read "/Users/alice/code"

# 现在（更加灵活）：
opencode --allow-read "~/code"`)])],-1),a('<hr><h2 id="功能回归-openai-模型的-todo-工具" tabindex="-1">功能回归：OpenAI 模型的 Todo 工具 <a class="header-anchor" href="#功能回归-openai-模型的-todo-工具" aria-label="Permalink to “功能回归：OpenAI 模型的 Todo 工具”">​</a></h2><h3 id="发生了什么" tabindex="-1">发生了什么？ <a class="header-anchor" href="#发生了什么" aria-label="Permalink to “发生了什么？”">​</a></h3><p>之前版本中，OpenAI 模型的 Todo List 工具暂时缺席了。在这个版本中，它回来了！</p><h3 id="有什么用" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用" aria-label="Permalink to “有什么用？”">​</a></h3><p>Todo List 工具允许 AI 在执行复杂任务时，自己创建一个任务清单，做完一项勾选一项。这对于长任务、多步骤任务非常重要，能防止 AI &quot;忘事&quot; 或 &quot;走偏&quot;。</p><h3 id="如何体验" tabindex="-1">如何体验？ <a class="header-anchor" href="#如何体验" aria-label="Permalink to “如何体验？”">​</a></h3><p>使用 OpenAI 模型（如 GPT-4o）进行复杂任务时，你可能会看到它主动列出计划：</p><ol><li>[ ] 分析代码结构</li><li>[ ] 修改配置文件</li><li>[ ] 运行测试</li></ol><p>这就是 Todo 工具在工作。</p><hr><h2 id="桌面版改进" tabindex="-1">桌面版改进 <a class="header-anchor" href="#桌面版改进" aria-label="Permalink to “桌面版改进”">​</a></h2><ul><li><strong>终端体验优化</strong>：修复了一些终端显示和交互的问题。</li><li><strong>OAuth 修复</strong>：登录第三方服务（如 GitHub）时更加稳定。</li></ul><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>经常配置路径白名单</td><td>✅ 推荐升级</td></tr><tr><td>使用 OpenAI 模型做复杂任务</td><td>✅ 强烈推荐</td></tr><tr><td>其他用户</td><td>可以升级</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',17),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Add session list and session fork support to ACP (@remorses)</li><li>Fix metadata matching to use model.id instead of model.api.id to support legacy model identifiers</li><li>Adjust textVerbosity and reasoningEffort defaults to better align with Codex CLI behavior</li><li>Implement home directory expansion for permission patterns using <code>~</code> and <code>$HOME</code> prefixes (@Danztee)</li><li>Add back todo list tools for OpenAI models</li><li>Persist loaded model and mode when loading ACP sessions (@noamzbr)</li><li>Update GitLab packages for better self-hosted instance support (@vglafirov)</li><li>Make the models.dev domain configurable for offline environments (@bartbroere)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Rename favicon on web again</li><li>Improve provider OAuth error handling in app</li><li>Fix renaming non-git projects affecting other projects</li><li>Tab should select suggestion in the app</li><li>Fix type error</li><li>Fix terminal issues and regressions</li><li>Remove terminal button border to align with close button (@allanhvam)</li><li>Fixed navigation issues when working with large sessions in desktop app (@dbpolito)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const _=t(l,[["render",d]]);export{m as __pageData,_ as default};
